  1→//! Branch-distance fitness function for genetic search.
  2→//!
  3→//! Scores an [`ExecuteResult`] on four axes — branch coverage, proximity
  4→//! to uncovered target branches, unknown-branch exploration bonus, and
  5→//! path novelty — and combines them into a single 0.0–1.0 fitness value.
  6→
  7→use std::collections::HashSet;
  8→
  9→use crate::execution_record::{BranchDecision, SymConstraint};
 10→use crate::orchestrator::hash_branch_path;
 11→use crate::protocol::ExecuteResult;
 12→use crate::sym_expr::{BinOpKind, ConstValue, SymExpr};
 13→
 14→/// Weights for combining the four fitness components.
 15→///
 16→/// Defaults: coverage 0.30, proximity 0.40, unknown_bonus 0.10, novelty 0.20.
 17→#[derive(Debug, Clone)]
 18→pub struct FitnessWeights {
 19→    pub coverage: f64,
 20→    pub proximity: f64,
 21→    pub unknown_bonus: f64,
 22→    pub novelty: f64,
 23→}
 24→
 25→impl Default for FitnessWeights {
 26→    fn default() -> Self {
 27→        Self {
 28→            coverage: 0.30,
 29→            proximity: 0.40,
 30→            unknown_bonus: 0.10,
 31→            novelty: 0.20,
 32→        }
 33→    }
 34→}
 35→
 36→/// Breakdown of the four fitness components before weighting.
 37→#[derive(Debug, Clone)]
 38→pub struct FitnessBreakdown {
 39→    /// Fraction of unique branches hit relative to target count (0.0–1.0).
 40→    pub coverage: f64,
 41→    /// Average closeness to flipping target branches (0.0–1.0).
 42→    pub proximity: f64,
 43→    /// Bonus for reaching `SymConstraint::Unknown` branches (0.0–1.0).
 44→    pub unknown_bonus: f64,
 45→    /// 1.0 if this is a novel path, 0.0 if previously seen.
 46→    pub novelty: f64,
 47→    /// Weighted combination of the four components (0.0–1.0).
 48→    pub total: f64,
 49→}
 50→
 51→/// Mutable state tracking previously seen path hashes for novelty scoring.
 52→#[derive(Debug, Clone, Default)]
 53→pub struct FitnessContext {
 54→    seen_paths: HashSet<u64>,
 55→}
 56→
 57→impl FitnessContext {
 58→    pub fn new() -> Self {
 59→        Self::default()
 60→    }
 61→}
 62→
 63→/// Score an execution result against a set of target (uncovered) branch IDs.
 64→///
 65→/// Returns a [`FitnessBreakdown`] with individual component scores and the
 66→/// weighted total, all normalized to 0.0–1.0.
 67→pub fn score(
 68→    result: &ExecuteResult,
 69→    target_branches: &HashSet<u32>,
 70→    context: &mut FitnessContext,
 71→    weights: &FitnessWeights,
 72→) -> FitnessBreakdown {
 73→    let coverage = coverage_score(&result.branch_path, target_branches.len());
 74→    let proximity = proximity_score(&result.branch_path, target_branches);
 75→    let unknown = unknown_bonus_score(&result.branch_path);
 76→    let novelty = novelty_score(&result.branch_path, context);
 77→
 78→    let weight_sum = weights.coverage + weights.proximity + weights.unknown_bonus + weights.novelty;
 79→    let total = if weight_sum > 0.0 {
 80→        (weights.coverage * coverage
 81→            + weights.proximity * proximity
 82→            + weights.unknown_bonus * unknown
 83→            + weights.novelty * novelty)
 84→            / weight_sum
 85→    } else {
 86→        0.0
 87→    };
 88→
 89→    FitnessBreakdown {
 90→        coverage,
 91→        proximity,
 92→        unknown_bonus: unknown,
 93→        novelty,
 94→        total,
 95→    }
 96→}
 97→
 98→// ---------------------------------------------------------------------------
 99→// Component scorers
100→// ---------------------------------------------------------------------------
101→
102→/// Fraction of unique branches hit relative to `target_count`.
103→fn coverage_score(branch_path: &[BranchDecision], target_count: usize) -> f64 {
104→    if target_count == 0 {
105→        return 1.0;
106→    }
107→    let unique: HashSet<u32> = branch_path.iter().map(|bd| bd.branch_id).collect();
108→    let ratio = unique.len() as f64 / target_count as f64;
109→    ratio.min(1.0)
110→}
111→
112→/// Average closeness to flipping each target branch.
113→///
114→/// For each target: if reached in the trace, score = 1 − branch_distance.
115→/// If never reached, contributes 0.
116→fn proximity_score(branch_path: &[BranchDecision], targets: &HashSet<u32>) -> f64 {
117→    if targets.is_empty() {
118→        return 1.0;
119→    }
120→    let mut total = 0.0;
121→    for &target_id in targets {
122→        let closest = branch_path
123→            .iter()
124→            .filter(|bd| bd.branch_id == target_id)
125→            .map(|bd| branch_distance(&bd.constraint))
126→            .min_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
127→
128→        if let Some(dist) = closest {
129→            total += 1.0 - dist;
130→        }
131→    }
132→    total / targets.len() as f64
133→}
134→
135→/// Distance for a single branch constraint (0.0 = at target, 1.0 = far away).
136→fn branch_distance(constraint: &SymConstraint) -> f64 {
137→    match constraint {
138→        SymConstraint::Unknown { .. } => 0.5,
139→        SymConstraint::Expr { expr } => expr_distance(expr),
140→    }
141→}
142→
143→/// Distance derived from a symbolic expression.
144→fn expr_distance(expr: &SymExpr) -> f64 {
145→    match expr {
146→        SymExpr::BinOp { op, left, right } => {
147→            match (eval_to_f64(left), eval_to_f64(right)) {
148→                (Some(l), Some(r)) => comparison_distance(*op, l, r),
149→                _ => 0.5, // cannot evaluate — moderate distance
150→            }
151→        }
152→        SymExpr::UnOp {
153→            op: crate::sym_expr::UnOpKind::Not,
154→            operand,
155→        } => 1.0 - expr_distance(operand),
156→        _ => 0.5,
157→    }
158→}
